@using sv_f937098ca46442f5a24bd6c69c3f9923.Services
@inject IChatService ChatService
@inject IJSRuntime JS
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left sidebar: channel list ── *@
    <aside class="sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var channel in _channels)
                {
                    <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <main class="message-area @(_threadOpen ? "thread-open" : "")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h2># @_activeChannel.Name</h2>
                <span class="message-header-desc">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="OnMessageListScroll">
                @if (_loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-row" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="message-bubble">
                                <div class="message-meta">
                                    <span class="message-author">@msg.Author</span>
                                    <span class="message-time">@FormatRelativeTime(msg.SentAt)</span>
                                </div>
                                <div class="message-content">@msg.Content</div>

                                @if (msg.Reactions.Count > 0)
                                {
                                    <div class="reaction-row">
                                        @foreach (var reaction in msg.Reactions)
                                        {
                                            <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                                                @reaction.Emoji @reaction.Users.Count
                                            </span>
                                        }
                                    </div>
                                }

                                @{ var threadInfo = GetThreadSummary(msg.Id); }
                                @if (threadInfo is not null)
                                {
                                    <button class="thread-link" @onclick="() => OpenThreadAsync(msg)"
                                            @onclick:stopPropagation="true">
                                        @threadInfo.ReplyCount @(threadInfo.ReplyCount == 1 ? "reply" : "replies")
                                    </button>
                                }
                            </div>

                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg)">💬 Reply</button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="action-btn" title="Add reaction"
                                                @onclick="() => ToggleEmojiPicker(msg.Id)">😊 React</button>
                                        @if (_emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in _commonEmojis)
                                                {
                                                    <button class="emoji-option"
                                                            @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                        @emoji
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2" placeholder="Type a message…"
                          @bind="_newMessageText" @bind:event="oninput"
                          @onkeydown="OnMessageKeyDown" />
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </main>

    @* ── Right panel: thread view ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <div class="message-meta">
                    <span class="message-author">@_threadRootMessage.Author</span>
                    <span class="message-time">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                </div>
                <div class="message-content">@_threadRootMessage.Content</div>
            </div>

            <div class="thread-replies">
                @if (_threadMessages is not null)
                {
                    @foreach (var reply in _threadMessages)
                    {
                        <div class="message-bubble thread-reply">
                            <div class="message-meta">
                                <span class="message-author">@reply.Author</span>
                                <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>
                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var reaction in reply.Reactions)
                                    {
                                        <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </span>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2" placeholder="Reply in thread…"
                          @bind="_threadReplyText" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDown" />
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(_threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel>? _channels;
    private Channel? _activeChannel;
    private int? _activeChannelId;

    private List<Message>? _messages;
    private int _messageSkip;
    private bool _loadingOlder;
    private bool _allOlderLoaded;

    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadMessages;

    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;
    private string _newMessageText = "";
    private string _threadReplyText = "";

    private ElementReference _messageListRef;

    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannelAsync(_channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        _activeChannel = channel;
        _activeChannelId = channel.Id;
        _messageSkip = 0;
        _allOlderLoaded = false;
        _messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messageSkip = _messages.Count;

        await BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channel list to update unread counts
        _channels = await ChatService.GetChannelsAsync();

        CloseThread();
        await ScrollToBottom();
    }

    private async Task BuildThreadSummaries()
    {
        _threadSummaries.Clear();
        if (_messages is null) return;

        // Identify messages that are thread roots (have replies pointing to them)
        var rootIds = _messages
            .Where(m => m.ReplyToId is not null)
            .Select(m => m.ReplyToId!.Value)
            .Distinct()
            .ToHashSet();

        // Also include messages that are themselves roots (no ReplyToId) and have replies
        foreach (var rootId in rootIds)
        {
            var replies = _messages.Where(m => m.ReplyToId == rootId).ToList();
            if (replies.Count > 0)
            {
                _threadSummaries[rootId] = new ThreadSummary(
                    rootId,
                    replies.Count,
                    replies.Max(r => r.SentAt)
                );
            }
        }
    }

    private ThreadSummary? GetThreadSummary(int messageId)
    {
        return _threadSummaries.GetValueOrDefault(messageId);
    }

    private async Task OnMessageListScroll()
    {
        if (_loadingOlder || _allOlderLoaded || _activeChannel is null) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            await LoadOlderMessagesAsync();
        }
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (_activeChannel is null || _loadingOlder || _allOlderLoaded) return;

        _loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannel.Id, _messageSkip, PageSize);
        if (older.Count == 0)
        {
            _allOlderLoaded = true;
        }
        else
        {
            _messages = [..older, ..(_messages ?? [])];
            _messageSkip += older.Count;
            await BuildThreadSummaries();
        }

        _loadingOlder = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannel is null) return;

        var msg = await ChatService.SendMessageAsync(_activeChannel.Id, _newMessageText.Trim(), null);
        _messages ??= [];
        _messages.Add(msg);
        _messageSkip++;
        _newMessageText = "";
        await ScrollToBottom();
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    private async Task OpenThreadAsync(Message rootMessage)
    {
        // If the message is itself a reply, open the thread for its root
        var rootId = rootMessage.ReplyToId ?? rootMessage.Id;
        var root = _messages?.FirstOrDefault(m => m.Id == rootId) ?? rootMessage;

        _threadRootMessage = root;
        _threadMessages = await ChatService.GetThreadAsync(root.Id);
        _threadReplyText = "";
        _threadOpen = true;
        _emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = null;
        _threadReplyText = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootMessage is null || _activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannel.Id, _threadReplyText.Trim(), _threadRootMessage.Id);
        _threadMessages ??= [];
        _threadMessages.Add(reply);
        _threadReplyText = "";

        // Update thread summary count
        var existing = _threadSummaries.GetValueOrDefault(_threadRootMessage.Id);
        _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(
            _threadRootMessage.Id,
            (existing?.ReplyCount ?? 0) + 1,
            reply.SentAt
        );
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Refresh messages to show updated reactions
        if (_activeChannel is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannel.Id, 0, _messageSkip);
        }

        // Also refresh thread if open
        if (_threadOpen && _threadRootMessage is not null)
        {
            _threadMessages = await ChatService.GetThreadAsync(_threadRootMessage.Id);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task ScrollToBottom()
    {
        await Task.Yield();
        try
        {
            await JS.InvokeVoidAsync("eval",
                "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
        }
        catch { /* Component may not be rendered yet */ }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }

    private static string TruncateDescription(string description)
    {
        return description.Length > 50 ? description[..47] + "…" : description;
    }
}
"}

